import { useState } from "react";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);
    const [file, setFile] = useState(null);
    const [fileName, setFileName] = useState("");
    const [loading, setLoading] = useState(false);
    const [uploadMessage, setUploadMessage] = useState("");

    const analyzeResume = async () => {
        if (!resumeText) return;

        setLoading(true);

        const res = await fetch("http://localhost:5000/analyze", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({ resumeText, jobDescription })
        });

        const data = await res.json();
        setAnalysis(data);
        setLoading(false);
    };

    const uploadResume = async () => {
        if (!file) {
            setUploadMessage("Please select a PDF first.");
            return;
        }

        setLoading(true);

        const formData = new FormData();
        formData.append("resume", file);

        const res = await fetch("http://localhost:5000/upload", {
            method: "POST",
            body: formData
        });

        const data = await res.json();

        if (data.extractedText) {
            setResumeText(data.extractedText);
        }

        setUploadMessage(data.message);
        setLoading(false);
    };

    const tagStyle = (bg, color) => ({
        padding: "8px 14px",
        borderRadius: "20px",
        margin: "6px",
        fontSize: "14px",
        fontWeight: "600",
        background: bg,
        color: color,
        transition: "0.2s"
    });

    return (
        <div style={pageStyle}>
            <div style={cardStyle}>
                <h1 style={{ textAlign: "center" }}>AI Resume Analyzer 🚀</h1>

                {/* Upload */}
                <h3>Upload Resume (PDF)</h3>
                <input
                    type="file"
                    accept=".pdf"
                    onChange={(e) => {
                        setFile(e.target.files[0]);
                        setFileName(e.target.files[0]?.name || "");
                    }}
                />

                {fileName && <p>📄 {fileName}</p>}

                <button style={greenBtn} onClick={uploadResume}>
                    {loading ? "Uploading..." : "Upload & Extract"}
                </button>

                {uploadMessage && <p style={msgStyle}>{uploadMessage}</p>}

                {/* Resume */}
                <h3>Resume</h3>
                <textarea
                    style={inputStyle}
                    placeholder="Paste resume..."
                    value={resumeText}
                    onChange={(e) => setResumeText(e.target.value)}
                />

                {/* JD */}
                <h3>Job Description</h3>
                <textarea
                    style={inputStyle}
                    placeholder="Paste job description..."
                    value={jobDescription}
                    onChange={(e) => setJobDescription(e.target.value)}
                />

                <div style={{ textAlign: "center" }}>
                    <button style={blueBtn} onClick={analyzeResume}>
                        {loading ? "Analyzing..." : "Analyze Match"}
                    </button>
                </div>

                {/* RESULT */}
                {analysis && (
                    <div style={{ marginTop: "25px" }}>
                        <h2>🎯 Role: {analysis.role}</h2>

                        {/* Score */}
                        <div style={{ margin: "15px 0" }}>
                            <h3>Score: {analysis.score}%</h3>
                            <div style={barBg}>
                                <div
                                    style={{
                                        width: `${analysis.score}%`,
                                        height: "100%",
                                        background:
                                            analysis.score > 75
                                                ? "#28a745"
                                                : analysis.score > 50
                                                    ? "#ffc107"
                                                    : "#dc3545",
                                        transition: "width 1s"
                                    }}
                                />
                            </div>
                        </div>

                        <Section title="Required Skills">
                            {analysis.requiredKeywords.map((s, i) => (
                                <span key={i} style={tagStyle("#e9ecef", "#333")}>{s}</span>
                            ))}
                        </Section>

                        <Section title="Matched Skills">
                            {analysis.matchedSkills.map((s, i) => (
                                <span key={i} style={tagStyle("#d4edda", "#155724")}>{s}</span>
                            ))}
                        </Section>

                        <Section title="Missing Skills">
                            {analysis.missingSkills.map((s, i) => (
                                <span key={i} style={tagStyle("#f8d7da", "#721c24")}>{s}</span>
                            ))}
                        </Section>

                        <Section title="Suggestions">
                            <ul>
                                {analysis.suggestions.map((s, i) => (
                                    <li key={i}>{s}</li>
                                ))}
                            </ul>
                        </Section>
                    </div>
                )}
            </div>
        </div>
    );
}

/* COMPONENT */
const Section = ({ title, children }) => (
    <div style={sectionStyle}>
        <h3>{title}</h3>
        <div style={{ display: "flex", flexWrap: "wrap" }}>{children}</div>
    </div>
);

/* STYLES */
const pageStyle = {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #667eea, #764ba2)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "sans-serif"
};

const cardStyle = {
    width: "900px",
    background: "white",
    padding: "30px",
    borderRadius: "12px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.2)"
};

const inputStyle = {
    width: "100%",
    height: "120px",
    padding: "12px",
    marginTop: "10px",
    borderRadius: "8px",
    border: "1px solid #ccc"
};

const blueBtn = {
    marginTop: "15px",
    padding: "12px 20px",
    background: "#007bff",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
};

const greenBtn = {
    marginTop: "10px",
    padding: "10px 16px",
    background: "#28a745",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer"
};

const barBg = {
    height: "18px",
    background: "#ddd",
    borderRadius: "20px",
    overflow: "hidden"
};

const sectionStyle = {
    background: "#f8f9fa",
    padding: "15px",
    borderRadius: "8px",
    marginBottom: "15px"
};

const msgStyle = {
    background: "#e8f5e9",
    padding: "8px",
    borderRadius: "6px"
};

export default App;
